--- GetServerData()年轻犯的错，后面改正
function StructThingsDetailInfo:GetServerDataByPb(itype,pb)
	local data
	if itype == LItemTypeConst.TYPE_ITEM then							-- 道具
		local item = StructItem:New()
		item:CreateByPb(pb)
		data = item:GetServerData()
	elseif itype == LItemTypeConst.TYPE_HERO then						-- 英雄
		local hero = StructHero:New()
		hero:CreateByPb(pb)
		data = hero:GetServerData()
	elseif itype == LItemTypeConst.TYPE_EQUIP then						-- 装备
		local equip = StructEquip:New()
		equip:CreateByPb(pb)
		data = equip:GetServerData()
	elseif itype == LItemTypeConst.TYPE_RUNE then						-- 符文
		local rune = StructRune:New()
		rune:CreateByPb(pb)
		data = rune:GetServerData()
	elseif itype == LItemTypeConst.TYPE_OUTFIT then					-- 新装备
		local outfit = StructOutfit:New()
		outfit:CreateByPb(pb)
		data = outfit:GetServerData()
	elseif itype == LItemTypeConst.TYPE_EQUIP then					-- 装备
		---@type StructEquip
		local equip = StructEquip:New()
		equip:CreateByPb(pb)
		data = equip:GetServerData()
	elseif itype == LItemTypeConst.TYPE_PET_EQUIP then
		local petDetail = StructPetEquip.NewStructPetEquip()
		petDetail:CreateByPb(pb)
		data = petDetail:GetServerData()
	elseif itype == LItemTypeConst.TYPE_GOLEM then						-- 魔偶
		local golem = StructGolemInfo:New()
		golem:CreateByPb(pb)
		data = golem
	-- 【G公共支持】删除伙伴晶石功能相关数据
	-- elseif itype == LItemTypeConst.ICON_TYPE_CRYSTAL_SHARD then						-- 魔晶
	-- 	local crystal = StructCrystalInfo:New()
	-- 	crystal:CreateByPb(pb)
	-- 	data = crystal
	-- 【C宠物系统】删掉宠物系统相关
	-- elseif itype == LItemTypeConst.TYPE_PET then
	-- 	local petDetail = StructPetDetailInfo:New()
	-- 	petDetail:CreateByPb(pb)
	-- 	data = petDetail
	end
	return {
		serverData = data,
		detail = true,
	}
end


return StructThingsDetailInfo